import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as a,o as s,c as l,a as t,b as e,d,w as c,e as i}from"./app-cea43815.js";const h={},p=t("h1",{id:"cs-go",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#cs-go","aria-hidden":"true"},"#"),e(" CS:GO")],-1),u=i('<blockquote><p>另外，我已于 2022.11.20 戒掉了 CS:GO，且于 2023.01.28 卸载。<s>（不卸载的话效果不好）</s> 希望各位适度游戏，享受游戏过程。</p></blockquote><h2 id="设置方案" tabindex="-1"><a class="header-anchor" href="#设置方案" aria-hidden="true">#</a> 设置方案</h2><h3 id="启用控制台" tabindex="-1"><a class="header-anchor" href="#启用控制台" aria-hidden="true">#</a> 启用控制台</h3><figure><img src="https://cdn.staticaly.com/gh/lxl66566/lxl66566.github.io/images/hobbies/other_games/csgo/csgo_settings_1.png" alt="控制台" tabindex="0" loading="lazy"><figcaption>控制台</figcaption></figure><p>控制台是对csgo进行高级操作的基础。现在你可以按<code>~</code>键呼出控制台。</p><h3 id="切换国服" tabindex="-1"><a class="header-anchor" href="#切换国服" aria-hidden="true">#</a> 切换国服</h3><h4 id="如何切换" tabindex="-1"><a class="header-anchor" href="#如何切换" aria-hidden="true">#</a> 如何切换</h4><p>国服游玩csgo的优点是：</p><ul><li>无需加速器，延迟低</li><li>匹配国人队友</li></ul><p>不过切换国服也有缺点，比如需要防沉迷认证，无法跟外服联机等。请自行决定是否切换。你可以选择以下<strong>一项</strong>：</p>',10),g={href:"https://pvp.wanmei.com/",target:"_blank",rel:"noopener noreferrer"},m=i(`<div style="text-align:center;"><img alt="开始界面" src="https://cdn.staticaly.com/gh/lxl66566/lxl66566.github.io/images/hobbies/other_games/csgo/csgo_settings_2.png" width="43%" height="43%"></div><ul><li>在steam库中右击csgo，点击<code>属性</code>，在<code>通用-启动选项</code>中加入<code>-perfectworld</code></li></ul><h4 id="切换后的设置" tabindex="-1"><a class="header-anchor" href="#切换后的设置" aria-hidden="true">#</a> 切换后的设置</h4><p>由于切换国服后csgo的语音会变成中文，若需要切换回英文语音请：</p><ol><li>进入Steam安装目录下的Steam\\steamapps\\common\\Counter-Strike Global Offensive\\csgo文件夹</li><li>删除所有名称带有 audiochinese 的.vpk文件与全部三个名称带有 perfectworld 的.vpk文件 <em>（后者与语音无关，但建议删除）</em></li></ol><div class="hint-container tip"><p class="hint-container-title">提示</p><p>若更新后出现<strong>文件缺失提醒</strong>、<strong>素材加载失败</strong>或<strong>语音变回中文</strong>情况，请再次进入目录删除。</p></div><h3 id="调整纵横比" tabindex="-1"><a class="header-anchor" href="#调整纵横比" aria-hidden="true">#</a> 调整纵横比</h3><p>游戏默认比例16:9，但调整成4:3有如下好处：</p><ul><li>更容易爆头</li><li>分辨率更低，提高帧率（性能过剩的话当我没说）</li></ul><p>调整纵横比后，还需要将画面拉长以充分适应电脑屏幕。但是画面拉长有如下缺点：</p><ul><li>调整后的玩家头身比例会让你觉得奇怪，需要一段时间的适应</li><li>游戏开始时会改变已打开窗口的纵横比</li><li>鼠标的水平移动速率与垂直移动速率将不相等</li></ul><p>画面拉长的常规方法是进入NVIDIA控制面板进行设置。此处给出一种非常规的解决方案：</p><ol><li>Win+R 键进入运行，输入 regedit 打开注册表</li><li>依次点击 HKEY_LOCAL_MACHINE..SYSTEM..ControlSet001..Control..GraphicsDrivers..Configuration （此时每个目录下仅有一个文件夹，一直点到最后），在右侧找到 Scaling 并双击，更改数值为3</li></ol><div style="text-align:center;"><img alt="注册表" src="https://cdn.staticaly.com/gh/lxl66566/lxl66566.github.io/images/hobbies/other_games/csgo/csgo_settings_4.png" width="100%" height="100%"></div><div class="hint-container danger"><p class="hint-container-title">警告</p><p>对注册表进行直接操作前请务必事先备份！ <br><img alt="注册表备份" src="https://cdn.staticaly.com/gh/lxl66566/lxl66566.github.io/images/hobbies/other_games/csgo/csgo_settings_3.png" width="40%" height="40%"></p></div><h3 id="显示fps" tabindex="-1"><a class="header-anchor" href="#显示fps" aria-hidden="true">#</a> 显示FPS</h3><p>在控制台中输入<code>net_graph 1</code></p><p>该命令还能显示ping值，丢包率，tick等。</p><h3 id="显示回合伤害" tabindex="-1"><a class="header-anchor" href="#显示回合伤害" aria-hidden="true">#</a> 显示回合伤害</h3><p>每回合结束后在左上角显示本回合伤害数据：</p><ol><li>进入Steam安装目录下的 <em>Steam\\steamapps\\common\\Counter-Strike Global Offensive\\csgo\\cfg</em> 文件夹，新建文本文档，复制粘贴以下代码：</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>developer 1;
con_filter_enable 2;
con_filter_text_out &quot;player:&quot;;
con_filter_text &quot;damage&quot;;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>保存关闭后重命名为”damage.cfg”</li><li>在steam库中右击csgo，点击<code>属性</code>，在<code>通用-启动选项</code>中加入 +exec damage</li></ol><h3 id="一键跳投" tabindex="-1"><a class="header-anchor" href="#一键跳投" aria-hidden="true">#</a> 一键跳投</h3><p>比起手动跳投，一键跳投拥有更高的精确度。（理论上绝对精确）</p><p>在控制台输入：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>alias +jumpthrow&quot;+jump;-attack;-attack2&quot;
alias -jumpthrow -jump
bind &quot;t&quot; &quot;+jumpthrow&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>之后拉开投掷物后按<code>t</code>即可一键跳投。其中<code>t</code>也可更换为其他不冲突的按键。</p><h3 id="清除血迹" tabindex="-1"><a class="header-anchor" href="#清除血迹" aria-hidden="true">#</a> 清除血迹</h3><p><code>bind &quot;shift&quot; &quot;+speed;r_cleardecals&quot;</code> 或者 <code>bind f &quot;+lookatweapon;r_cleardecals&quot;</code></p><h3 id="一键大跳" tabindex="-1"><a class="header-anchor" href="#一键大跳" aria-hidden="true">#</a> 一键大跳</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>alias +cjump &quot;+jump; +duck&quot;
alias -cjump &quot;-jump; -duck&quot;
bind &quot;mouse5&quot; &quot;+cjump&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="缩小雷达图" tabindex="-1"><a class="header-anchor" href="#缩小雷达图" aria-hidden="true">#</a> 缩小雷达图</h3><p><code>cl_radar_scale 0.3</code>可以使雷达图包含的信息更多。</p><h3 id="快速切指定道具" tabindex="-1"><a class="header-anchor" href="#快速切指定道具" aria-hidden="true">#</a> 快速切指定道具</h3><p><code>bind &quot;6&quot; &quot;use weapon_smokegrenade&quot;</code></p><ul><li>闪光弹 weapon_flashbang</li><li>烟雾弹 weapon_smokegrenade</li><li>诱饵弹 weapon_decoy</li><li>手雷 weapon_hegrenade</li><li>燃烧弹 weapon_incgrenade</li></ul><h3 id="静步加快" tabindex="-1"><a class="header-anchor" href="#静步加快" aria-hidden="true">#</a> 静步加快</h3><p><code>bind &quot;c&quot;+moveup</code> 按<code>c</code>即可快速无声走路。仅适用于内格夫，开镜的SG 553和AUG。</p><h2 id="常用指令" tabindex="-1"><a class="header-anchor" href="#常用指令" aria-hidden="true">#</a> 常用指令</h2><p>多用于自定义服务器（创意工坊）。</p><table><thead><tr><th style="text-align:center;">用途</th><th style="text-align:center;">指令</th></tr></thead><tbody><tr><td style="text-align:center;">设置出生金钱</td><td style="text-align:center;"><code>mp_startmoney 16000</code></td></tr><tr><td style="text-align:center;">设置最高金钱</td><td style="text-align:center;"><code>mp_maxmoney 16000</code></td></tr><tr><td style="text-align:center;">设置局时</td><td style="text-align:center;"><code>mp_roundtime 60</code><br><code>mp_roundtime_defuse 60</code></td></tr><tr><td style="text-align:center;">设置最大局数</td><td style="text-align:center;"><code>mp_maxrounds 30</code></td></tr><tr><td style="text-align:center;">取消购买时空限制</td><td style="text-align:center;"><code>mp_buytime 99999</code><br><code>mp_buy_anywhere 1</code></td></tr><tr><td style="text-align:center;">设置开始时原地冻结时间</td><td style="text-align:center;"><code>mp_buytime</code></td></tr><tr><td style="text-align:center;">设置友伤</td><td style="text-align:center;"><code>mp_friendlyfire 0/1</code></td></tr><tr><td style="text-align:center;">设置可加入双方</td><td style="text-align:center;"><code>mp_humanteam any</code></td></tr><tr><td style="text-align:center;">设置时间流速</td><td style="text-align:center;"><code>host_timescale 20</code></td></tr><tr><td style="text-align:center;">无限弹药</td><td style="text-align:center;"><code>sv_infinite_ammo 1</code></td></tr><tr><td style="text-align:center;">显示着弹点</td><td style="text-align:center;"><code>sv_showimpacts 1</code></td></tr><tr><td style="text-align:center;">显示投掷物轨迹</td><td style="text-align:center;"><code>sv_grenade_trajectory 1</code></td></tr></tbody></table><h2 id="问题解决" tabindex="-1"><a class="header-anchor" href="#问题解决" aria-hidden="true">#</a> 问题解决</h2><p>无法连接到服务器可以尝试： cmd 中执行</p><div class="language-batch line-numbers-mode" data-ext="batch"><pre class="language-batch"><code><span class="token command"><span class="token keyword">netsh</span> winsock reset</span>
<span class="token command"><span class="token keyword">ipconfig</span> <span class="token parameter attr-name">/flushdns</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>有时候有用。</p>`,46);function x(b,_){const n=a("RouterLink"),o=a("ExternalLinkIcon");return s(),l("div",null,[p,t("p",null,[e("CS:GO确实是一款吸引我的游戏。但我打CS:GO会有罪恶感，因此需要"),d(n,{to:"/hide/personal_details.html#%E5%BC%BA%E8%BF%AB%E8%87%AA%E5%B7%B1%E5%81%9A%E7%9A%84%E4%BA%8B"},{default:c(()=>[e("时不时戒一段时间")]),_:1}),e("。")]),u,t("ul",null,[t("li",null,[e("下载安装"),t("a",g,[e("完美世界竞技平台"),d(o)]),e("软件。之后每次启动csgo时就会让你选择游玩哪个服务器。")])]),m])}const y=r(h,[["render",x],["__file","csgo.html.vue"]]);export{y as default};
